+import { promises as fs } from 'node:fs';
+import { join } from 'node:path';
+import { Type } from '@sinclair/typebox';
+import { ScipIndexer } from './core/indexer.js';
+import { ScipQuery, NeedsReindexError } from './core/query.js';
